import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
import numpy as np
from sklearn.metrics import roc_curve, auc
import os

def generate_roc_figure():
    # Load the probabilities generated by the pipeline
    data = np.load('roc_data.npz')
    y_true = data['y_true']
    y_probs = data['y_probs']
    
    fpr, tpr, _ = roc_curve(y_true, y_probs)
    roc_auc = auc(fpr, tpr)
    
    plt.figure(figsize=(8, 6))
    
    # Clean, dark blue ROC line
    plt.plot(fpr, tpr, color='darkblue', lw=3, label=f'Strict Nested LOO-CV (AUC = {roc_auc:.3f})')
    
    # Diagonal gray dashed line representing random chance
    plt.plot([0, 1], [0, 1], color='gray', lw=2, linestyle='--', label='Random Chance (AUC = 0.50)')
    
    plt.xlim([0.0, 1.0])
    plt.ylim([0.0, 1.05])
    plt.xlabel('False Positive Rate', fontsize=14)
    plt.ylabel('True Positive Rate', fontsize=14)
    plt.title('Receiver Operating Characteristic (ROC)', fontsize=16, weight='bold')
    plt.legend(loc="lower right", fontsize=12)
    plt.grid(True, alpha=0.3)
    
    output_dir = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "Results"))
    plt.tight_layout()
    plt.savefig(os.path.join(output_dir, 'path1_figure3_roc.png'), dpi=300, bbox_inches='tight')
    plt.close()

if __name__ == "__main__":
    import sys
    try:
        generate_roc_figure()
    except Exception as e:
        import traceback
        traceback.print_exc(file=sys.stderr)
        sys.exit(1)
